                    qqPlot = function() private$.items[["qqPlot"]],
                    barPlot = function() private$.items[["barPlot"]]),
                private = list(),
                public=list(
                    initialize=function(options) {
                        super$initialize(
                            options=options,
                            name="hweGroup",
                            title="Hardy-Weinberg Equilibrium (HWE) Analysis")
                        
                        self$add(jmvcore::Table$new(
                            options=options,
                            name="freqTable",
                            title="Genotype and Allele Frequencies",
                            visible="(freqTable)",
                            clearWith=list("vars", "group", "mafThreshold"),
                            columns=list(
                                list(`name`="marker", `title`="Marker", `type`="text"),
                                list(`name`="group", `title`="Population", `type`="text", `visible`="(group)"),
                                list(`name`="p_freq", `title`="p (A)", `type`="number"),
                                list(`name`="q_freq", `title`="q (B)", `type`="number"),
                                list(`name`="obsAA", `title`="Obs AA", `type`="text"),
                                list(`name`="obsAB", `title`="Obs AB", `type`="text"),
                                list(`name`="obsBB", `title`="Obs BB", `type`="text"),
                                list(`name`="expAA", `title`="Exp AA", `type`="text"),
                                list(`name`="expAB", `title`="Exp AB", `type`="text"),
                                list(`name`="expBB", `title`="Exp BB", `type`="text"),
                                list(`name`="h_obs", `title`="H(obs)", `type`="number"),
                                list(`name`="h_exp", `title`="H(exp)", `type`="number")
                            )
                        ))
                        
                        self$add(jmvcore::Table$new(
                            options=options,
                            name="hwTable",
                            title="Hardy-Weinberg Equilibrium Statistical Tests",
                            visible="(hwTests)",
                            clearWith=list("vars", "group", "hwPerm", "nPerm", "adjust"),
                            columns=list(
                                list(`name`="marker", `title`="Marker", `type`="text"),
                                list(`name`="group", `title`="Population", `type`="text", `visible`="(group)"),
                                list(`name`="chi_stat", `title`="χ²", `type`="number"),
                                list(`name`="chi_p", `title`="Chi-square p", `type`="number"),
                                list(`name`="chi_p_adj", `title`="Chi-square p-adj", `type`="number"),
                                list(`name`="exact_p", `title`="Exact p", `type`="number"),
                                list(`name`="exact_p_adj", `title`="Exact p-adj", `type`="number"),
                                list(`name`="lr_stat", `title`="LRT Stat", `type`="number"),
                                list(`name`="lr_p", `title`="LRT p", `type`="number"),
                                list(`name`="lr_p_adj", `title`="LRT p-adj", `type`="number"),
                                list(`name`="perm_p", `title`="Permutation p", `type`="number", `visible`="(hwPerm)"),
                                list(`name`="perm_p_adj", `title`="Permutation p-adj", `type`="number", `visible`="(hwPerm)"),
                                list(`name`="fis", `title`="F_IS", `type`="number")
                            )
                        ))
                        
                        self$add(jmvcore::Image$new(
