                            height=450,
                            renderFun=".plotQQ",
                            requiresData=TRUE,
                            visible="(qqPlot)",
                            clearWith=list("vars", "group", "hwPerm")
                        ))
                        
                        self$add(jmvcore::Image$new(
                            options=options,
                            name="barPlot",
                            title="Genotype barplot (Observed vs Expected)",
                            width=650,
                            height=450,
                            renderFun=".plotBar",
                            requiresData=TRUE,
                            visible="(barPlot)",
