                            columns=list(
                                list(`name`="marker", `title`="Marker", `type`="text"),
                                list(`name`="model", `title`="Genetic model", `type`="text"),
                                list(`name`="counts_cases", `title`="Genotypes Cases", `type`="text"),
                                list(`name`="counts_ctrls", `title`="Genotypes Controls", `type`="text"),
