                        ))
                    }
                }
            )$new(options=options))
            
            # Population Group
            self$add(R6::R6Class(
                inherit = jmvcore::Group,
                active = list(
                    popTable = function() private$.items[["popTable"]]),
                private = list(),
                public=list(
                    initialize=function(options) {
                        super$initialize(
