                    mdrCellTable = function() private$.items[["mdrCellTable"]],
                    mdrHeatmap = function() private$.items[["mdrHeatmap"]],
                    mdrBarPlot = function() private$.items[["mdrBarPlot"]]),
                private = list(),
                public=list(
                    initialize=function(options) {
                        super$initialize(
